#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void generate(char *str, int left, int right, int n, char ***result, int *returnSize) {
    if (strlen(str) == 2 * n) {
        (*returnSize)++;
        (*result) = realloc((*result), (*returnSize) * sizeof(char *));
        (*result)[(*returnSize) - 1] = malloc((strlen(str) + 1) * sizeof(char));
        strcpy((*result)[(*returnSize) - 1], str);
        return;
    }
    if (left < n) {
        str[strlen(str)] = '(';
        generate(str, left + 1, right, n, result, returnSize);
        str[strlen(str)] = '\0';
    }
    if (right < left) {
        str[strlen(str)] = ')';
        generate(str, left, right + 1, n, result, returnSize);
        str[strlen(str)] = '\0';
    }
}

char **generateParenthesis(int n, int *returnSize) {
    char **result = NULL;
    *returnSize = 0;
    char str[2 * n + 1];
    str[0] = '\0';
    generate(str, 0, 0, n, &result, returnSize);
    return result;
}

