#include <bits/stdc++.h>
using namespace std;

void generate(string str, int left, int right, int n, vector<string>& result) {
    if (str.length() == 2 * n) {
        result.push_back(str);
        return;
    }
    if (left < n) {
        generate(str + "(", left + 1, right, n, result);
    }
    if (right < left) {
        generate(str + ")", left, right + 1, n, result);
    }
}

vector<string> generateParenthesis(int n) {
    vector<string> result;
    generate("", 0, 0, n, result);
    return result;
}

code.Java:
import java.util.*;

class Solution {
    public List<String> generateParenthesis(int n) {
        List<String> result = new ArrayList<>();
        generate(result, new StringBuilder(), 0, 0, n);
        return result;
    }

    private void generate(List<String> result, StringBuilder current, int left, int right, int n) {
        if (current.length() == 2 * n) {
            result.add(current.toString());
            return;
        }
        if (left < n) {
            current.append('(');
            generate(result, current, left + 1, right, n);
            current.deleteCharAt(current.length() - 1);
        }
        if (right < left) {
            current.append(')');
            generate(result, current, left, right + 1, n);
            current.deleteCharAt(current.length() - 1);
        }
    }
}

